module Foo(
  input clock,
  input reset
);
  reg r;
  always @(posedge clock) begin
    if (reset)
      r <= 1'h1;
    else
      r <= 1'h0;
  end
endmodule

reg dead_r;
always @(posedge clock) begin
  if (reset)
    dead_r <= 1'b1;
  else
    dead_r <= 1'b0;
end

module DeadMod(
  input clock,
  input reset
);
  reg r1;
  reg r2;
  always @(posedge clock) begin
    if (reset) begin
      r1 <= 1'b0;
      r2 <= 1'b0;
    end else begin
      r1 <= ~r1;
      r2 <= r1;
    end
  end
endmodule
